mapper.select:
SELECT * FROM(
	SELECT id,concat('1') type,`name` name,address,brand,adcode,phone,concat('0') indentNumber,concat('0') money,DATE_FORMAT(create_time,'%Y-%m-%d') createTime,concat('1') state
	 FROM app_up_merchants
	 	where 1 = 1

			AND address like "%"#{address,jdbcType=VARCHAR}"%"


			AND name like "%"#{selectName,jdbcType=VARCHAR}"%"


			AND brand = #{selectBrand}


			AND citycode = #{selectAdcode}


		UNION ALL
	SELECT id,concat('2') type,merchants_name name,address,brand_id brand ,city adcode,phone_number phone,concat('0') indentNumber,concat('0') money,DATE_FORMAT(creat_time,'%Y-%m-%d') createTime,state
	FROM app_b_user WHERE is_merchants = 1

			AND address like "%"#{address,jdbcType=VARCHAR}"%"


			AND merchants_name like "%"#{selectName,jdbcType=VARCHAR}"%"


			AND brand_id = #{selectBrand}


			AND city = #{selectAdcode}

)as a ORDER BY a.createTime DESC LIMIT #{pageoffset},20;

SELECT count(1) FROM(
	SELECT `name` name FROM app_up_merchants
where 1 = 1

	AND address like "%"#{address,jdbcType=VARCHAR}"%"


	AND name like "%"#{selectName,jdbcType=VARCHAR}"%"


	AND brand = #{selectBrand}


	AND citycode = #{selectAdcode}

		UNION ALL
	SELECT merchants_name name
	FROM app_b_user WHERE is_merchants = 1

	AND address like "%"#{address,jdbcType=VARCHAR}"%"


	AND merchants_name like "%"#{selectName,jdbcType=VARCHAR}"%"


	AND brand_id = #{selectBrand}


	AND city = #{selectAdcode}

)as a

SELECT DISTINCT brand FROM app_up_merchants

	id in

		#{item}

SELECT id ,address,lng,lat,name,brand,adcode,citycode FROM app_up_merchants

	id in

		#{id}
